import{_ as i,o as a,c as s,ai as t}from"./chunks/framework.BXTfpgaI.js";const c=JSON.parse('{"title":"[git] git worktree","description":"","frontmatter":{"title":"[git] git worktree","date":"2026-05-17T00:00:00.000Z","issue":4,"issueUrl":"https://github.com/iysun/blogs/issues/4","labels":[],"syncedFromIssue":true,"layout":"IssuePostLayout","pageClass":"blog-doc"},"headers":[],"relativePath":"issue-4.md","filePath":"issue-4.md"}'),l={name:"issue-4.md"};function r(n,e,h,o,d,g){return a(),s("div",null,[...e[0]||(e[0]=[t('<p>我在工作中经常需要在同一个项目的不同分支上写代码， 使用 git worktree 实际上可以让我不用总是切换分支</p><h2 id="git-worktree-怎么用" tabindex="-1">git worktree 怎么用 <a class="header-anchor" href="#git-worktree-怎么用" aria-label="Permalink to “git worktree 怎么用”">​</a></h2><h3 id="_1-创建新的工作树" tabindex="-1">1. <strong>创建新的工作树</strong> <a class="header-anchor" href="#_1-创建新的工作树" aria-label="Permalink to “1. 创建新的工作树”">​</a></h3><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>git worktree add &lt;路径&gt; &lt;分支&gt;</span></span></code></pre></div><ul><li>创建一个新的工作树并将指定分支检出到该工作树中。例如：</li></ul><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>git worktree add ../my-feature-branch feature-branch</span></span></code></pre></div><ul><li>这会在当前仓库目录外的 <code>../my-feature-branch</code> 目录中创建一个新的工作树，并将 <code>feature-branch</code> 分支检出。</li></ul><h3 id="_2-移除工作树" tabindex="-1">2. <strong>移除工作树</strong> <a class="header-anchor" href="#_2-移除工作树" aria-label="Permalink to “2. 移除工作树”">​</a></h3><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>git worktree remove &lt;路径&gt;</span></span></code></pre></div><ul><li>移除指定路径的工作树。例如：</li></ul><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>git worktree remove -f ../my-feature-branch</span></span></code></pre></div><ul><li>这会删除 <code>../my-feature-branch</code> 工作树，注意工作树内的修改不会丢失，仓库本身的数据不会受影响。</li></ul><h3 id="_3-列出所有工作树" tabindex="-1">3. <strong>列出所有工作树</strong> <a class="header-anchor" href="#_3-列出所有工作树" aria-label="Permalink to “3. 列出所有工作树”">​</a></h3><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>git worktree list</span></span></code></pre></div><ul><li>显示当前仓库的所有工作树及其状态。</li></ul><h3 id="_4-清理孤立的工作树" tabindex="-1">4. <strong>清理孤立的工作树</strong> <a class="header-anchor" href="#_4-清理孤立的工作树" aria-label="Permalink to “4. 清理孤立的工作树”">​</a></h3><div class="language-plain"><button title="Copy Code" class="copy"></button><span class="lang">plain</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>git worktree prune</span></span></code></pre></div><ul><li>删除所有已被移除的工作树，清理磁盘空间。</li></ul>',18)])])}const k=i(l,[["render",r]]);export{c as __pageData,k as default};
